import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { ArrowLeft, Loader2 } from 'lucide-react';
import './WalletActions.css';

export default function AddFunds() {
  const navigate = useNavigate();
  const [amount, setAmount] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const quickAmounts = [100, 500, 1000, 2000];

  const handleAddFunds = async () => {
    setError('');

    if (!amount || amount <= 0) {
      setError('Enter a valid amount');
      return;
    }

    if (amount < 10) {
      setError('Minimum amount is ₹10');
      return;
    }

    setLoading(true);

    try {
      // 🔥 Replace with real API call (Razorpay/Stripe)
      await new Promise((res) => setTimeout(res, 1500));

      alert(`₹${amount} added successfully`);
      navigate('/wallet');

    } catch (err) {
      setError('Payment failed. Try again.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="wallet-action-container">

      {/* Header */}
      <div className="wallet-action-header">
        <button onClick={() => navigate(-1)}><ArrowLeft /></button>
        <h2>Add Money</h2>
      </div>

      {/* Amount Input */}
      <div className="wallet-card">
        <label>Enter Amount</label>
        <input
          type="number"
          placeholder="₹ Enter amount"
          value={amount}
          onChange={(e) => setAmount(e.target.value)}
        />

        {/* Quick Select */}
        <div className="quick-amounts">
          {quickAmounts.map(val => (
            <button key={val} onClick={() => setAmount(val)}>
              ₹{val}
            </button>
          ))}
        </div>

        {error && <p className="error">{error}</p>}
      </div>

      {/* Action Button */}
      <button 
        className="primary-btn" 
        onClick={handleAddFunds}
        disabled={loading}
      >
        {loading ? <Loader2 className="spin" /> : 'Add Money'}
      </button>

    </div>
  );
}
